import jwt
from datetime import datetime, timedelta

class JWTWrapper:
    def __init__(self, algorithm='HS256', secret_key=None):
        self.algorithm = algorithm
        self.secret_key = secret_key

    def verify_token(self, token):
        try:
            payload = jwt.decode(token, self.secret_key, algorithms=self.algorithm)
            return payload
        except jwt.ExpiredSignatureError:
            print("Token has expired.")
            raise
        except jwt.InvalidTokenError as e:
            print(f"Invalid Token: {e}")
            raise

    def generate_token(self, payload):
        if self.algorithm == 'HS256':
            return jwt.encode(payload, self.secret_key, algorithm=self.algorithm)
        elif self.algorithm == 'RS256':
            header = {'alg': 'RS256'}
            encoded_header = jwt.encode(header, self.secret_key, algorithm='PS256')
            return jwt.encode(payload, encoded_header, algorithm='RS256')


# Example usage
jwt_wrapper = JWTWrapper(algorithm='HS256', secret_key='secret_key')

payload = {
    'username': 'john_doe',
    'exp': datetime.utcnow() + timedelta(minutes=30)
}

token = jwt_wrapper.generate_token(payload)

